import time
from prometheus_client import Counter, Gauge, generate_latest, REGISTRY
from flask import Flask, request, Response
import threading

app = Flask(__name__)

metrics_lock = threading.Lock()
user_path_metrics = {}

request_counter = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

def get_or_create_user_path_metric(user_id, path):
    metric_key = f"{user_id}_{path}"
    
    with metrics_lock:
        if metric_key not in user_path_metrics:
            safe_user_id = user_id.replace('-', '_').replace('.', '_')
            safe_path = path.replace('/', '_').replace('-', '_').replace('.', '_')
            metric_name = f'user_path_requests_{safe_user_id}{safe_path}'
            
            user_path_metrics[metric_key] = Counter(
                metric_name,
                f'Requests for user {user_id} on path {path}',
                ['user_id', 'session_id', 'path', 'method']
            )
        
        return user_path_metrics[metric_key]

@app.before_request
def track_request():
    request.start_time = time.time()

@app.after_request
def record_metrics(response):
    user_id = request.headers.get('X-User-Id', 'anonymous')
    session_id = request.headers.get('X-Session-Id', 'no_session')
    path = request.path
    method = request.method
    status = response.status_code
    
    request_counter.labels(method=method, endpoint=path, status=status).inc()
    
    user_path_metric = get_or_create_user_path_metric(user_id, path)
    user_path_metric.labels(
        user_id=user_id,
        session_id=session_id,
        path=path,
        method=method
    ).inc()
    
    return response

@app.route('/metrics')
def metrics():
    return Response(generate_latest(REGISTRY), mimetype='text/plain')

@app.route('/')
def index():
    return {'message': 'Hello World'}

@app.route('/api/data')
def api_data():
    return {'data': 'some data'}

@app.route('/api/users/<user_id>')
def api_user(user_id):
    return {'user_id': user_id}

@app.route('/health')
def health():
    return {'status': 'healthy'}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)